text:
pre {
  background: var(--r-bg);
  border: 1px solid var(--r-line);
  border-radius: 0;
  padding: 14px 18px;
  font-family: 'JetBrains Mono', monospace;
  font-size: 13px;
  overflow-x: auto;

  code {
    background: transparent;
    border: none;
    padding: 0;
    color: var(--r-text);
  }
}

&-ping-top::before,
      &-ping-bottom::after {
        position: absolute;
        right: 0;
        left: 0;
        content: '';
      }
      &-ping-top::before {
        top: 0;
        border-top: 1px solid red;
      }
      &-ping-bottom::after {
        bottom: 0;
        border-top: 1px solid red;
      }

&.btn-lg {
    .btn-lg; /* reference to admin-lte/buttons.less */

    span.ui-icon {
        width: 22px;
        height: 20px;
        margin-top:-8px;
        &:before {
            font-size: @font-awesome-icon2x-size
        }
    }

    &.ui-button-text-icon-right, &.ui-button-text-icon-left  {
        padding: 6px 16px;
    }
}

> a {
  padding: 5px 5px 5px 15px;
  display: block;
  font-size: 14px;
  > .fa,
  > .glyphicon,
  > .ion {
    width: 20px;
  }
  > .pull-right-container > .fa-angle-left,
  > .pull-right-container > .fa-angle-down,
  > .fa-angle-left,
  > .fa-angle-down {
    width: auto;
  }
}

img {
  position: relative;
  display: block;
  max-width: 100%;
  max-height: 100%;
  //max-width:100%;
  //height:auto;
  opacity: 0;
  z-index: 200;
  -webkit-user-drag: none;
  transition: opacity .2s ease-in;

  &.@{ns}img-loaded {
    opacity: 1;
  }
}

&[data-site-mode='true'] {
  padding-top: @s-nav-height + 50px;

  &[data-show-sidemenu='true'] {
    padding-left: @s-site-menu-width + 50px;
  }

  .@{prefix}-layout-content > .markdown:first-child > *:first-child {
    margin-top: 0;
  }

  .@{prefix}-layout-toc {
    top: 114px;
    max-height: calc(90vh - 144px);
  }
}

&-thumb {
  width: 28px;
  height: 28px;
  margin: 2px;
  border-radius: 50%;
  text-align: center;
  line-height: 28px;
  background: var(--adm-color-text-light-solid);
  box-shadow: 0 2px 5px 0 rgba(0, 0, 0, 0.12);
  color: var(--fill-color);
  &:focus {
    outline: none;
  }
}

footer.dark {
  background-color: #000;
  color: rgba(255, 255, 255, 0.65);
  a {
    color: rgba(255, 255, 255, 0.9);
  }
  h2 {
    color: rgba(255, 255, 255, 1);
    & >span {
      color: rgba(255, 255, 255, 1);
    }
  }
  .bottom-bar {
    overflow: hidden;
  }
}

&-footer {
  display: flex;
  width: 100%;
  align-items: center;
  border-top: 1rpx solid @border-color-base;
  padding: 10px 0;
  margin: -4px 0 0;
  font-size: 14px;
  line-height: 20px;
  color: @color-text-caption;
  image {
    width: 14px;
    height: 14px;
    margin-right: 4px;
  }
}

#MathJax_AboutClose,
    #MathJax_HelpClose {
      border-color: @surface2;
      color: @subtext0;
      span {
        background-color: @surface2;
      }

      &:hover {
        color: @text !important;
        border-color: @overlay0 !important;
        span {
          background-color: @overlay0 !important;
        }
      }
    }

&-small{
    th{
        height: 32px;
    }
    td{
        height: 40px;
    }
    &-title, &-footer{
        height: 40px;
        line-height: 40px;
    }
    .@{table-prefix-cls}-cell-with-expand{
        height: 39px;
        line-height: 39px;
    }
}

@media screen and (min-width: 600px) {

    ::-webkit-scrollbar-thumb {
        background: var(--dark-primary);
    }

    ::-webkit-scrollbar-thumb:hover {
        background: var(--dark-primary);
    }

    ::-webkit-scrollbar-thumb:active {
        background: var(--dark-primary);
    }
}

li[class~="cbi-tab"] {
  border-bottom: 0.18751rem solid #5e72e4;
  border-bottom: 0.18751rem solid var(--primary);
  color: #5e72e4;
  color: var(--primary);
  background-color: #e4e9ee;
  margin-bottom: 0;

  a {
    color: #5e72e4;
    color: var(--primary);
  }
}

#config-items-list {
  :is(th, td) {
    padding: 8px 12px;
  }
  :is(tr:hover, td.gray) {
    background-color: @color-fade2;
  }
  th,
  td:not(:last-child) {
    border-color: @border-darker;
  }
  :is(.envvar_prefix, td.redacted) {
    opacity: 1;
    color: @color-fade5;
  }
}

& + .trm-swich {
	margin-bottom: 0;
	box-shadow: var(--box-shadow);
	background: var(--theme-bg2-color, #f4f5f7);
	border-radius: 2em;
	padding: 2px;
	.transition-mixin();

	&:after {
		width: 47%;
		border: solid 3px var(--primary, #afb42b);
		border-radius: 50%;
		background: var(--theme-bg-color, #fcfcfe);
		.transition-mixin(all, 0.2s);
	}
}

&.progress-active {
	cursor: progress;

	.rest {
		.transform(translate3d(0,-100%,0));
		opacity: 0;
	}
    .active {
		.transform(translate3d(0, -50%,0));
		opacity: 1;
	}


	&:before { .transform(translateY(0%)); }
	.progress-bar { .transform(translateX(0%));}
}

&.speed-dial-opened {
    .floating-button {
        i {
            .transform(translate3d(-50%, -50%, 0) rotate(90deg) scale(0.5));
            opacity: 0;
        }
        i + i {
            .transform(translate3d(-50%, -50%, 0) rotate(0deg) scale(1));
            opacity: 1;
        }
    }
}

@media (width <= 1280px), (height <= 800px) {
  .tree-view {
    .project-root.project-root {
      &::before {
        height: @tab-height * 0.8;
      }

      & > .header {
        & .name {
          height: @tab-height * 0.8 + 1px;
          line-height: @tab-height * 0.8;
        }
      }
    }
  }
}

#loading-message {
  text-align: center;
  font-size: 28px;
  font-weight: 200;
  color: white;
  position: absolute;
  left: 50%;
  top: 50%;
  height: 28px;
  width: 100%;
  transform: translate(-50%, -50%);
  img {
    vertical-align: middle;
    margin-bottom: 4px;
  }
}

&__dialog-table-item {
  width: 100%;
  display: flex;
  align-items: center;
  justify-content: space-between;

  &:nth-child(even) {
    background: var(--tv-PopUpload-table-item-even-bg-color);
  }

  .del-col {
    color: var(--tv-PopUpload-dialog-delete-text-color);
    width: 100%;
    cursor: pointer;
  }
}

// Z-index
@zindex-spin            : 8;
@zindex-affix           : 10;
@zindex-back-top        : 10;
@zindex-select          : 900;
@zindex-modal           : 1000;
@zindex-drawer          : 1000;
@zindex-message         : 1010;
@zindex-notification    : 1010;
@zindex-tooltip         : 1060;
@zindex-transfer        : 1060;
@zindex-loading-bar     : 2000;
@zindex-spin-fullscreen : 2010;

// Avatar
@avatar-size-base: 32px;
@avatar-size-lg: 40px;
@avatar-size-sm: 24px;
@avatar-font-size-base: 18px;
@avatar-font-size-lg: 24px;
@avatar-font-size-sm: 14px;
@avatar-bg: #ccc;
@avatar-color: #fff;
@avatar-border-radius: @border-radius-small;

&-5 {
	flex-wrap: nowrap;
	padding-right: @size-1;
	padding-right: var(--am-grid-5-paddingRight, @size-1);
	&__overHide {
		overflow: hidden;
		padding-right: 0;
		& :nth-child(5) {
			padding-right: @size-1;
			padding-right: var(--am-grid-5-paddingRight, @size-1);
		}
	}
	&__wrap {
		flex-wrap: wrap;
	}
}

&-no-extra {
  padding-left: @size-5;
  padding-left: var(--am-coupon-no-extra-spacingL, @size-5);
  border-radius: @corner-radius-lg;
  &-text {
    margin-left: 0;
  }
  .am-coupon-content-detail-more {
    padding-right: @size-20;
    padding-right: var(--am-coupon-no-extra-detail-padding, @size-20);
  }
}

&-name {
  font-size: @avatar-fontSize-3;
  font-size: var(--am-avatar-name-size, @avatar-fontSize-3);
  color: @color-text-title;
  color: var(--am-avatar-name-color, @color-text-title);
  &-lg {
    font-size: @avatar-fontSize-4;
    font-size: var(--am-avatar-name-size-lg, @avatar-fontSize-4);
  }
}

&-button-wrap {
  .amFormat(margin-top, am-message-margintop, @size-5);
  padding: 0 @size-3;
  padding: 0 var(--am-message-button-margin, @size-3);

  & .a-button {
    margin-bottom: @size-3;
    margin-bottom: var(--am-message-button-margin, @size-3);
  }
}

&-desc {
  margin-top: @avatar-desc-between-space;
  margin-top: var(--am-avatar-desc-marginT, @avatar-desc-between-space);
  font-size: @avatar-fontSize-2;
  font-size: var(--am-avatar-desc-fontSize, @avatar-fontSize-2);
  color: @color-text-subtitle;
  color: var(--am-avatar-desc-color, @color-text-subtitle);
  &-xs {
    display: none;
  }
}

@-webkit-keyframes fadeOutUpCenter {
  0% {
    opacity: 1;
    transform: translateY(-50%);
    -webkit-transform: translateY(calc(-50% - 0.5px));
  }
  100% {
    opacity: 0;
    transform: translateY(-45%);
    -webkit-transform: translateY(calc(-45% - 0.5px));
  }
}

@-webkit-keyframes fadeInUpCenter {
  0% {
    opacity: 0;
    transform: translateY(-40%);
    -webkit-transform: translateY(calc(-40% - 0.5px));
  }
  100% {
    opacity: 1;
    transform: translateY(-50%);
    -webkit-transform: translateY(calc(-50% - 0.5px));
  }
}

@keyframes fadeOutDownCenter {
  0% {
    opacity: 1;
    transform: translateY(-50%);
    -webkit-transform: translateY(calc(-50% - 0.5px));
  }
  100% {
    opacity: 0;
    transform: translateY(-55%);
    -webkit-transform: translateY(calc(-55% - 0.5px));
  }
}
